#!/usr/bin/env sh
set -eu

ROOT_DIR=$(CDPATH= cd -- "$(dirname -- "$0")/../../../.." && pwd)
PUBLIC_DIR="${MAPLIBRE_PUBLIC_DIR:-$ROOT_DIR/data/middleware/maplibre/public}"
DEFAULT_STYLE_FILE="${MAPLIBRE_STYLE_FILE:-$ROOT_DIR/third-party/middleware/maplibre/public/style.json}"
GLYPHS_BASE_URL="${MAPLIBRE_GLYPHS_BASE_URL:-https://fonts.openmaptiles.org}"
FONTSTACK="${MAPLIBRE_FONTSTACK:-Noto Sans Regular}"
RANGES="${MAPLIBRE_GLYPH_RANGES-0-255 256-511 512-767 768-1023 1024-1279 1280-1535 1536-1791 1792-2047 19968-20223 20224-20479 20480-20735 20736-20991 20992-21247 21248-21503 21504-21759 21760-22015 22016-22271 22272-22527 22528-22783 22784-23039 23040-23295 23296-23551 23552-23807 23808-24063 24064-24319 24320-24575 24576-24831 24832-25087 25088-25343 25344-25599 25600-25855 25856-26111 26112-26367 26368-26623 26624-26879 26880-27135 27136-27391 27392-27647 27648-27903 27904-28159 28160-28415 28416-28671 28672-28927 28928-29183 29184-29439 29440-29695 29696-29951 29952-30207 30208-30463 30464-30719 30720-30975 30976-31231 31232-31487 31488-31743 31744-31999 32000-32255 32256-32511 32512-32767 32768-33023 33024-33279 33280-33535 33536-33791 33792-34047 34048-34303 34304-34559 34560-34815 34816-35071 35072-35327 35328-35583 35584-35839 35840-36095 36096-36351 36352-36607 36608-36863 36864-37119 37120-37375 37376-37631 37632-37887 37888-38143 38144-38399 38400-38655 38656-38911 38912-39167 39168-39423 39424-39679 39680-39935 39936-40191 40192-40447 40448-40703 40704-40959}"

mkdir -p "$PUBLIC_DIR/fonts"

if [ -f "$DEFAULT_STYLE_FILE" ] && [ ! -f "$PUBLIC_DIR/style.json" ]; then
  cp "$DEFAULT_STYLE_FILE" "$PUBLIC_DIR/style.json"
fi

font_dir="$PUBLIC_DIR/fonts/$FONTSTACK"
mkdir -p "$font_dir"
encoded_fontstack=$(printf '%s' "$FONTSTACK" | sed 's/ /%20/g')
for range in $RANGES; do
  target="$font_dir/$range.pbf"
  if [ -s "$target" ]; then
    continue
  fi
  HTTP_PROXY= HTTPS_PROXY= ALL_PROXY= \
  http_proxy= https_proxy= all_proxy= \
  NO_PROXY='*' no_proxy='*' \
  curl --fail --location --show-error --progress-bar --noproxy '*' \
    "$GLYPHS_BASE_URL/$encoded_fontstack/$range.pbf" \
    --output "$target.tmp"
  mv "$target.tmp" "$target"
done

mkdir -p "$PUBLIC_DIR/sprites"
printf '{}\n' > "$PUBLIC_DIR/sprites/sprite.json"
printf '{}\n' > "$PUBLIC_DIR/sprites/sprite@2x.json"
printf 'iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mP8z8BQDwAFgwJ/lvLj1AAAAABJRU5ErkJggg==' | base64 -d > "$PUBLIC_DIR/sprites/sprite.png"
printf 'iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mP8z8BQDwAFgwJ/lvLj1AAAAABJRU5ErkJggg==' | base64 -d > "$PUBLIC_DIR/sprites/sprite@2x.png"

echo "Downloaded MapLibre glyph assets for $FONTSTACK into $PUBLIC_DIR"
